'use client';

import { useState, useMemo, useEffect } from 'react';
import { Table, TableBody, TableCell, TableHead, TableHeader, TableRow } from '@/components/ui/table';
import { Input } from '@/components/ui/input';
import { Badge } from '@/components/ui/badge';
import type { LogEntry } from '@/types';
import { cn } from '@/lib/utils';
import { ScrollArea } from '@/components/ui/scroll-area';
import { Checkbox } from './ui/checkbox';
import { Label } from './ui/label';
import { Button } from './ui/button';
import { Popover, PopoverContent, PopoverTrigger } from './ui/popover';
import { Command, CommandEmpty, CommandGroup, CommandInput, CommandItem, CommandList } from './ui/command';
import { CheckIcon, ChevronsUpDown } from 'lucide-react';


const levelConfig: Record<string, { badge: 'destructive' | 'secondary' | 'default' | 'outline', color: string }> = {
  ERROR: { badge: 'destructive', color: 'text-destructive' },
  WARN: { badge: 'default', color: 'text-primary' },
  INFO: { badge: 'secondary', color: 'text-accent-foreground' },
  DEBUG: { badge: 'outline', color: 'text-muted-foreground' },
  UNKNOWN: { badge: 'outline', color: 'text-muted-foreground' },
};


export function LogViewer({ logs }: {logs: LogEntry[]}) {
  const [searchTerm, setSearchTerm] = useState('');
  
  const allCategories = useMemo(() => {
    if (!logs) return [];
    return Array.from(new Set(logs.map(log => log.category || 'Uncategorized'))).sort();
  }, [logs]);

  const [selectedCategories, setSelectedCategories] = useState<Set<string>>(new Set(allCategories));

  useEffect(() => {
    setSelectedCategories(new Set(allCategories));
  }, [allCategories]);

  const handleCategoryChange = (category: string, checked: boolean) => {
    setSelectedCategories(prev => {
      const newSet = new Set(prev);
      if (checked) {
        newSet.add(category);
      } else {
        newSet.delete(category);
      }
      return newSet;
    });
  };

  const filteredLogs = useMemo(() => {
    return logs.filter((log) => {
      const categoryMatch = selectedCategories.has(log.category || 'Uncategorized');
      const searchMatch = searchTerm ? log.originalLine.toLowerCase().includes(searchTerm.toLowerCase()) : true;
      return categoryMatch && searchMatch;
    });
  }, [logs, searchTerm, selectedCategories]);

  return (
    <div className="space-y-4">
      <div className="flex flex-col sm:flex-row gap-4 justify-between">
        <Input
          placeholder="Search logs..."
          value={searchTerm}
          onChange={(e) => setSearchTerm(e.target.value)}
          className="max-w-sm"
        />
        <Popover>
            <PopoverTrigger asChild>
                <Button variant="outline" className="w-[200px] justify-between">
                    Filter Categories
                    <ChevronsUpDown className="ml-2 h-4 w-4 shrink-0 opacity-50" />
                </Button>
            </PopoverTrigger>
            <PopoverContent className="w-[200px] p-0">
                <Command>
                    <CommandInput placeholder="Search categories..." />
                    <CommandList>
                        <CommandEmpty>No categories found.</CommandEmpty>
                        <CommandGroup>
                        {allCategories.map(category => (
                            <CommandItem
                                key={category}
                                onSelect={() => handleCategoryChange(category, !selectedCategories.has(category))}
                                className="cursor-pointer"
                            >
                                <CheckIcon
                                    className={cn(
                                        "mr-2 h-4 w-4",
                                        selectedCategories.has(category) ? "opacity-100" : "opacity-0"
                                    )}
                                />
                                {category}
                            </CommandItem>
                        ))}
                        </CommandGroup>
                    </CommandList>
                </Command>
            </PopoverContent>
        </Popover>
      </div>
      <ScrollArea className="h-[600px] rounded-md border">
        <Table>
          <TableHeader className="sticky top-0 bg-card z-10">
            <TableRow>
              <TableHead className="w-[220px]">Timestamp</TableHead>
              <TableHead className="w-[100px]">Level</TableHead>
              <TableHead>Message</TableHead>
            </TableRow>
          </TableHeader>
          <TableBody>
            {filteredLogs.map((log) => (
              <TableRow key={log.id}>
                <TableCell className="font-code text-xs text-muted-foreground">
                  {log.timestamp?.toLocaleString() ?? 'N/A'}
                </TableCell>
                <TableCell>
                  <Badge variant={levelConfig[log.level]?.badge ?? 'outline'}>{log.level}</Badge>
                </TableCell>
                <TableCell className={cn("font-code text-xs", levelConfig[log.level]?.color ?? 'text-foreground')}>
                  {log.message}
                </TableCell>
              </TableRow>
            ))}
             {filteredLogs.length === 0 && (
                <TableRow>
                    <TableCell colSpan={3} className="h-24 text-center">
                        No results found.
                    </TableCell>
                </TableRow>
            )}
          </TableBody>
        </Table>
      </ScrollArea>
    </div>
  );
}
