'use client';
import { useState, useEffect } from 'react';
import { detectLogAnomalies, type DetectLogAnomaliesOutput } from '@/ai/flows/detect-log-anomalies';
import { summarizeLogs } from '@/ai/flows/summarize-logs';
import { categorizeLogs } from '@/ai/flows/categorize-logs';
import { Header } from '@/components/Header';
import { LogUploader } from '@/components/LogUploader';
import { AnalysisDashboard } from '@/components/AnalysisDashboard';
import type { LogEntry } from '@/types';
import { BotMessageSquare, FileText } from 'lucide-react';
import pako from 'pako';

// Helper functions for URL state
const compressAndEncode = (str: string): string => {
  if (!str) return '';
  // Convert string to Uint8Array before compressing
  const textEncoder = new TextEncoder();
  const data = textEncoder.encode(str);
  const compressed = pako.deflate(data);
  // Convert Uint8Array to a binary string for btoa
  const binaryString = String.fromCharCode.apply(null, Array.from(compressed));
  return btoa(binaryString);
};

const decodeAndDecompress = (encoded: string): string => {
  if (!encoded) return '';
  try {
    const binaryString = atob(encoded);
    const compressed = new Uint8Array(binaryString.length);
    for (let i = 0; i < binaryString.length; i++) {
        compressed[i] = binaryString.charCodeAt(i);
    }
    const decompressed = pako.inflate(compressed);
    // Convert decompressed Uint8Array back to string
    const textDecoder = new TextDecoder();
    return textDecoder.decode(decompressed);
  } catch (e) {
    console.error("Failed to decode or decompress data from URL", e);
    // Clear invalid hash
    window.location.hash = '';
    return '';
  }
};


export function ClientPage() {
  const [logData, setLogData] = useState('');
  const [parsedLogs, setParsedLogs] = useState<LogEntry[]>([]);
  const [anomalySummary, setAnomalySummary] = useState('');
  const [anomalySolutions, setAnomalySolutions] = useState<DetectLogAnomaliesOutput['solutions']>([]);
  const [logSummary, setLogSummary] = useState('');
  const [isLoading, setIsLoading] = useState(false);
  const [analysisPerformed, setAnalysisPerformed] = useState(false);
  const [isInitialLoad, setIsInitialLoad] = useState(true);

  // Effect to run analysis from URL on initial load
  useEffect(() => {
    if (window.location.hash) {
      const decodedData = decodeAndDecompress(window.location.hash.substring(1));
      if (decodedData) {
        setLogData(decodedData);
        // Defer analysis to allow state to update before firing
        setTimeout(() => handleAnalyze(decodedData), 0);
      }
    }
    setIsInitialLoad(false);
  // eslint-disable-next-line react-hooks/exhaustive-deps
  }, []); // Run only once on mount

  const handleAnalyze = async (data: string | null = null) => {
    const currentLogData = data ?? logData;
    if (!currentLogData.trim()) return;

    setIsLoading(true);
    setAnalysisPerformed(true);
    
    if (!isInitialLoad) {
        const encoded = compressAndEncode(currentLogData);
        window.history.replaceState(null, '', '#' + encoded);
    }

    try {
      const [anomalyResult, summaryResult, categorizationResult] = await Promise.all([
        detectLogAnomalies({ logData: currentLogData }),
        summarizeLogs({ logData: currentLogData }),
        categorizeLogs({ logData: currentLogData }),
      ]);

      const categorizedEntries: LogEntry[] = categorizationResult.logs.map((log, index) => ({
        id: index,
        originalLine: log.originalLine,
        timestamp: log.timestamp ? new Date(log.timestamp) : null,
        level: log.level.toUpperCase(),
        message: log.message,
        category: log.category || 'Uncategorized',
      }));
      setParsedLogs(categorizedEntries);

      setAnomalySummary(anomalyResult.summary);
      setAnomalySolutions(anomalyResult.solutions);
      setLogSummary(summaryResult.summary);
    } catch (error) {
      console.error('AI analysis failed:', error);
      setAnomalySummary('An error occurred during anomaly detection.');
      setLogSummary('An error occurred during log summarization.');
      setAnomalySolutions([]);
      setParsedLogs([]);
    } finally {
      setIsLoading(false);
    }
  };

  return (
    <div className="min-h-screen flex flex-col">
      <Header />
      <main className="flex-1 container mx-auto p-4 sm:p-6 lg:p-8">
        <div className="grid grid-cols-1 lg:grid-cols-3 gap-8 items-start">
          <div className="lg:col-span-1 lg:sticky lg:top-8">
            <LogUploader
              logData={logData}
              setLogData={setLogData}
              onAnalyze={() => handleAnalyze()}
              isLoading={isLoading}
            />
          </div>
          <div className="lg:col-span-2">
            {analysisPerformed ? (
              isLoading ? (
                <div className="flex flex-col items-center justify-center h-96 rounded-lg border border-dashed">
                  <BotMessageSquare className="h-16 w-16 text-muted-foreground animate-pulse" />
                  <p className="mt-4 text-muted-foreground">AI is analyzing your logs...</p>
                </div>
              ) : (
                <AnalysisDashboard
                  logs={parsedLogs}
                  anomalySummary={anomalySummary}
                  logSummary={logSummary}
                  anomalySolutions={anomalySolutions}
                />
              )
            ) : (
              <div className="flex flex-col items-center justify-center h-96 rounded-lg border border-dashed">
                <FileText className="h-16 w-16 text-muted-foreground" />
                <p className="mt-4 text-muted-foreground text-center">Your analysis results will appear here.</p>
                <p className="mt-1 text-xs text-muted-foreground text-center">Paste a shared URL to load a session.</p>
              </div>
            )}
          </div>
        </div>
      </main>
    </div>
  );
}
